  1→package connector
  2→
  3→import (
  4→	"fmt"
  5→	"io/fs"
  6→	"os"
  7→	"path/filepath"
  8→	"sort"
  9→	"strings"
 10→)
 11→
 12→var builtinConnectorDefs = []ConnectorDef{
 13→	{
 14→		ID:       "linkedin",
 15→		Name:     "LinkedIn",
 16→		Type:     "social",
 17→		Tier:     2,
 18→		Required: false,
 19→		Def: &YAMLConnector{
 20→			SchemaVersion: 1,
 21→			ID:            "linkedin",
 22→			Name:          "LinkedIn",
 23→			Type:          "social",
 24→			Tier:          2,
 25→			Required:      false,
 26→			Description:   "LinkedIn via Nurge's server-managed Unipile connection flow",
 27→			Auth: AuthConfig{
 28→				Method: "oauth2",
 29→			},
 30→		},
 31→	},
 32→}
 33→
 34→// IsBundled returns true if a connector with the given ID is shipped as a
 35→// bundled YAML definition or hard-coded built-in. Bundled connectors cannot
 36→// be removed via "connectors remove".
 37→func IsBundled(id string) bool {
 38→	// Check hard-coded built-ins first.
 39→	for _, def := range builtinConnectorDefs {
 40→		if def.ID == id {
 41→			return true
 42→		}
 43→	}
 44→	// Check embedded YAML definitions.
 45→	_, err := bundledDefinitions.ReadFile("definitions/" + id + ".yaml")
 46→	return err == nil
 47→}
 48→
 49→// LoadRegistry scans bundled definitions and project-local definitions,
 50→// returning a merged list. Project-local definitions can override bundled
 51→// Tier 2/3 connectors but NOT Tier 1 (email providers).
 52→// projectDir is the path to .nurge/connectors/definitions/ (empty string to skip).
 53→func LoadRegistry(projectDir string) ([]ConnectorDef, error) {
 54→	defs := make(map[string]ConnectorDef)
 55→
 56→	// 1. Load bundled definitions
 57→	entries, err := fs.ReadDir(bundledDefinitions, "definitions")
 58→	if err != nil {
 59→		return nil, fmt.Errorf("reading bundled definitions: %w", err)
 60→	}
 61→	for _, entry := range entries {
 62→		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
 63→			continue
 64→		}
 65→		data, err := bundledDefinitions.ReadFile("definitions/" + entry.Name())
 66→		if err != nil {
 67→			fmt.Fprintf(os.Stderr, "warning: could not read bundled definition %s: %v\n", entry.Name(), err)
 68→			continue
 69→		}
 70→		yamlDef, err := ParseYAML(data)
 71→		if err != nil {
 72→			fmt.Fprintf(os.Stderr, "warning: invalid bundled connector definition %s: %v\n", entry.Name(), err)
 73→			continue
 74→		}
 75→		if _, exists := defs[yamlDef.ID]; exists {
 76→			fmt.Fprintf(os.Stderr, "warning: duplicate bundled connector definition %q, last one wins\n", yamlDef.ID)
 77→		}
 78→		defs[yamlDef.ID] = ConnectorDef{
 79→			ID:       yamlDef.ID,
 80→			Name:     yamlDef.Name,
 81→			Type:     yamlDef.Type,
 82→			Tier:     yamlDef.Tier,
 83→			Required: yamlDef.Required,
 84→			Def:      yamlDef,
 85→		}
 86→	}
 87→
 88→	// 2. Add server-managed built-ins that don't have a YAML definition yet.
 89→	for _, def := range builtinConnectorDefs {
 90→		if _, exists := defs[def.ID]; !exists {
 91→			defs[def.ID] = def
 92→		}
 93→	}
 94→
 95→	// 3. Load project-local definitions (override Tier 2/3 only)
 96→	if projectDir != "" {
 97→		localEntries, err := os.ReadDir(projectDir)
 98→		if err == nil { // silently skip if dir doesn't exist
 99→			for _, entry := range localEntries {
100→				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
101→					continue
102→				}
103→
104→				// Validate that definition file names don't contain path traversal characters
105→				if strings.Contains(entry.Name(), "..") || strings.ContainsAny(entry.Name(), "/\\") {
106→					fmt.Fprintf(os.Stderr, "warning: skipping connector definition with suspicious filename: %s\n", entry.Name())
107→					continue
108→				}
109→
110→				data, err := os.ReadFile(filepath.Join(projectDir, entry.Name()))
111→				if err != nil {
112→					fmt.Fprintf(os.Stderr, "warning: could not read project-local definition %s: %v\n", entry.Name(), err)
113→					continue
114→				}
115→				yamlDef, err := ParseYAML(data)
116→				if err != nil {
117→					fmt.Fprintf(os.Stderr, "warning: invalid project-local connector definition %s: %v\n", entry.Name(), err)
118→					continue
119→				}
120→				// Tier 1 connectors cannot be overridden
121→				if existing, ok := defs[yamlDef.ID]; ok && existing.Tier == 1 {
122→					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q ignored (Tier 1 connectors cannot be overridden)\n", yamlDef.ID)
123→					continue
124→				}
125→				// Log warning when overriding a Tier 2/3 connector
126→				if existing, ok := defs[yamlDef.ID]; ok {
127→					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q overrides bundled Tier %d connector\n", yamlDef.ID, existing.Tier)
128→				}
129→				defs[yamlDef.ID] = ConnectorDef{
130→					ID:       yamlDef.ID,
131→					Name:     yamlDef.Name,
132→					Type:     yamlDef.Type,
133→					Tier:     yamlDef.Tier,
134→					Required: yamlDef.Required,
135→					Def:      yamlDef,
136→				}
137→			}
138→		}
139→	}
140→
141→	// Convert to sorted slice: email first (required), then crm, then enrichment
142→	typeOrder := map[string]int{
143→		"email":        0,
144→		"social":       1,
145→		"crm":          2,
146→		"enrichment":   3,
147→		"sequencing":   4,
148→		"notification": 5,
149→		"webhook":      6,
150→	}
151→	result := make([]ConnectorDef, 0, len(defs))
152→	for _, d := range defs {
153→		result = append(result, d)
154→	}
155→	sort.Slice(result, func(i, j int) bool {
156→		oi := typeOrder[result[i].Type]
157→		oj := typeOrder[result[j].Type]
158→		if oi != oj {
159→			return oi < oj
160→		}
161→		return result[i].Name < result[j].Name
162→	})
163→
164→	return result, nil
165→}
166→

  1→package connector
  2→
  3→import (
  4→	"fmt"
  5→	"net/url"
  6→
  7→	"gopkg.in/yaml.v3"
  8→)
  9→
 10→// YAMLConnector is the parsed representation of a connector YAML file.
 11→type YAMLConnector struct {
 12→	SchemaVersion int          `yaml:"schema_version"`
 13→	ID            string       `yaml:"id"`
 14→	Name          string       `yaml:"name"`
 15→	Type          string       `yaml:"type"`
 16→	Tier          int          `yaml:"tier"`
 17→	Required      bool         `yaml:"required"`
 18→	Description   string       `yaml:"description"`
 19→	Icon          string       `yaml:"icon"`
 20→	Auth         AuthConfig                `yaml:"auth"`
 21→	Credentials  CredConfig                `yaml:"credentials"`
 22→	Verify       VerifyConfig              `yaml:"verify"`
 23→	Proxy        ProxyConfig               `yaml:"proxy"`
 24→	Variables    map[string]VariableConfig `yaml:"variables,omitempty"`
 25→	APIReference []APIEndpoint             `yaml:"api_reference,omitempty"`
 26→}
 27→
 28→// AuthConfig describes how to authenticate with the service.
 29→type AuthConfig struct {
 30→	Method       string            `yaml:"method"` // oauth2, api_key, basic, webhook
 31→	AuthorizeURL string            `yaml:"authorize_url"`
 32→	TokenURL     string            `yaml:"token_url"`
 33→	Scopes       []string          `yaml:"scopes"`
 34→	AuthStyle    string            `yaml:"auth_style"`   // in_params, in_header
 35→	ExtraParams  map[string]string `yaml:"extra_params"`
 36→	// api_key fields
 37→	Header     string `yaml:"header"`
 38→	QueryParam string `yaml:"query_param"`
 39→	EnvVar     string `yaml:"env_var"`
 40→	// basic auth fields
 41→	UsernameVar string `yaml:"username_var"`
 42→	PasswordVar string `yaml:"password_var"`
 43→	// webhook fields
 44→	URLVar string `yaml:"url_var"`
 45→}
 46→
 47→// CredConfig describes where credentials come from.
 48→type CredConfig struct {
 49→	Source          string `yaml:"source"` // env, bundled, google_json, file, prompt
 50→	ClientIDVar     string `yaml:"client_id_var"`
 51→	ClientSecretVar string `yaml:"client_secret_var"`
 52→}
 53→
 54→// VerifyConfig describes the connection verification call.
 55→type VerifyConfig struct {
 56→	URL           string            `yaml:"url"`
 57→	Method        string            `yaml:"method"`
 58→	Headers       map[string]string `yaml:"headers"`
 59→	AccountFields []string          `yaml:"account_fields"`
 60→	AccountLabel  string            `yaml:"account_label"`
 61→}
 62→
 63→// ProxyConfig describes how to call the service's API.
 64→type ProxyConfig struct {
 65→	BaseURL    string `yaml:"base_url"`
 66→	AuthHeader string `yaml:"auth_header"`
 67→}
 68→
 69→// VariableConfig describes a user-prompted variable (e.g., subdomain).
 70→type VariableConfig struct {
 71→	Prompt   string `yaml:"prompt"`
 72→	Required bool   `yaml:"required"`
 73→}
 74→
 75→// APIEndpoint describes a single API endpoint for the companion reference.
 76→type APIEndpoint struct {
 77→	Method      string   `yaml:"method"`
 78→	Path        string   `yaml:"path"`
 79→	Description string   `yaml:"description"`
 80→	Params      []string `yaml:"params,omitempty"`
 81→}
 82→
 83→// ParseYAML parses and validates a connector YAML definition.
 84→func ParseYAML(data []byte) (*YAMLConnector, error) {
 85→	var def YAMLConnector
 86→	if err := yaml.Unmarshal(data, &def); err != nil {
 87→		return nil, fmt.Errorf("parsing YAML: %w", err)
 88→	}
 89→	if err := validateDef(&def); err != nil {
 90→		return nil, err
 91→	}
 92→	// Defaults
 93→	if def.Tier == 0 {
 94→		def.Tier = 2
 95→	}
 96→	if def.Verify.Method == "" {
 97→		def.Verify.Method = "GET"
 98→	}
 99→	return &def, nil
100→}
101→
102→func validateDef(d *YAMLConnector) error {
103→	// Compatibility note: only schema_version 1 is currently supported.
104→	// Future versions may add new fields or change semantics. Definitions
105→	// with a different schema_version are rejected to prevent silent
106→	// misinterpretation of newer formats.
107→	if d.SchemaVersion != 1 {
108→		return fmt.Errorf("connector definition has unsupported schema_version: %d (expected 1)", d.SchemaVersion)
109→	}
110→	if d.ID == "" {
111→		return fmt.Errorf("connector definition missing required field: id")
112→	}
113→	if d.Name == "" {
114→		return fmt.Errorf("connector %q missing required field: name", d.ID)
115→	}
116→	if d.Type == "" {
117→		return fmt.Errorf("connector %q missing required field: type", d.ID)
118→	}
119→	if d.Auth.Method == "" {
120→		return fmt.Errorf("connector %q missing required field: auth.method", d.ID)
121→	}
122→
123→	// Validate variables: required ones must have a prompt.
124→	for name, vc := range d.Variables {
125→		if vc.Required && vc.Prompt == "" {
126→			return fmt.Errorf("connector %q variable %q is required but has no prompt", d.ID, name)
127→		}
128→	}
129→
130→	switch d.Auth.Method {
131→	case "oauth2":
132→		if d.Auth.AuthorizeURL == "" {
133→			return fmt.Errorf("connector %q (oauth2) missing auth.authorize_url", d.ID)
134→		}
135→		if d.Auth.TokenURL == "" {
136→			return fmt.Errorf("connector %q (oauth2) missing auth.token_url", d.ID)
137→		}
138→
139→		// Validate that AuthorizeURL and TokenURL are valid URLs
140→		if _, err := url.ParseRequestURI(d.Auth.AuthorizeURL); err != nil {
141→			return fmt.Errorf("connector %q (oauth2) has invalid auth.authorize_url %q: %w", d.ID, d.Auth.AuthorizeURL, err)
142→		}
143→		if _, err := url.ParseRequestURI(d.Auth.TokenURL); err != nil {
144→			return fmt.Errorf("connector %q (oauth2) has invalid auth.token_url %q: %w", d.ID, d.Auth.TokenURL, err)
145→		}
146→
147→		// Validate that scopes are non-empty for OAuth2
148→		if len(d.Auth.Scopes) == 0 {
149→			return fmt.Errorf("connector %q (oauth2) has empty auth.scopes (at least one scope is required)", d.ID)
150→		}
151→
152→	case "api_key":
153→		if d.Auth.Header == "" && d.Auth.QueryParam == "" {
154→			return fmt.Errorf("connector %q (api_key) missing auth.header or auth.query_param", d.ID)
155→		}
156→	case "basic":
157→		// valid -- credentials resolved at connect time
158→	case "webhook":
159→		// valid -- URL resolved at connect time
160→	default:
161→		return fmt.Errorf("connector %q has unknown auth.method: %q", d.ID, d.Auth.Method)
162→	}
163→
164→	return nil
165→}
