12→var verifyCmd = &cobra.Command{
13→	Use:   "verify [id]",
14→	Short: "Verify connector health (all connectors if no id given)",
15→	Args:  cobra.MaximumNArgs(1),
16→	RunE: func(cmd *cobra.Command, args []string) error {
17→		cfg, err := project.Load()
18→		if err != nil {
19→			return fmt.Errorf("loading config: %w", err)
20→		}
21→
22→		var targets []string
23→		if len(args) > 0 {
24→			id := args[0]
25→			if _, ok := cfg.Connectors[id]; !ok {
26→				return fmt.Errorf("unknown connector: %s\n  Run `nurge connectors` to see connected services", id)
27→			}
28→			targets = []string{id}
29→		} else {
30→			for id, cs := range cfg.Connectors {
31→				if cs.Connected {
32→					targets = append(targets, id)
33→				}
34→			}
35→			sort.Strings(targets)
36→		}
37→
38→		if len(targets) == 0 {
39→			fmt.Println("  No connectors configured")
40→			return nil
41→		}
42→
43→		allOK := true
44→		for _, id := range targets {
45→			cs := cfg.Connectors[id]
46→			connDir := fmt.Sprintf(".nurge/connectors/%s", id)
47→			convexBacked := id == "gmail" || id == "linkedin" || id == "hubspot" || id == "slack"
48→			result := connector.CheckHealth(id, connDir, cs.Connected, convexBacked)
49→			switch result.Status {
50→			case connector.HealthOK:
51→				fmt.Printf("  \033[32m✓\033[0m %-15s healthy\n", id)
52→			default:
53→				allOK = false
54→				fmt.Printf("  \033[31m✗\033[0m %-15s %s\n", id, result.Message)
55→			}
56→		}
57→		if !allOK {
58→			return fmt.Errorf("some connectors have issues, run `nurge connect <id>` to fix")
59→		}
60→		return nil
61→	},
62→}
