 27→// ── Signature verification ──────────────────────────────────────────
 28→
 29→async function verifySlackSignature(
 30→  request: Request,
 31→  rawBody: string
 32→): Promise<boolean> {
 33→  const signingSecret = process.env.SLACK_SIGNING_SECRET;
 34→  if (!signingSecret) {
 35→    console.warn("SLACK_SIGNING_SECRET not set - skipping signature verification");
 36→    return true; // Degrade gracefully in dev
 37→  }
 38→
 39→  const timestamp = request.headers.get("X-Slack-Request-Timestamp");
 40→  const signature = request.headers.get("X-Slack-Signature");
 41→
 42→  if (!timestamp || !signature) return false;
 43→
 44→  // Reject requests older than 5 minutes (replay attack prevention)
 45→  const now = Math.floor(Date.now() / 1000);
 46→  if (Math.abs(now - parseInt(timestamp)) > 300) return false;
 47→
 48→  const sigBasestring = `v0:${timestamp}:${rawBody}`;
 49→  const key = await crypto.subtle.importKey(
 50→    "raw",
 51→    new TextEncoder().encode(signingSecret),
 52→    { name: "HMAC", hash: "SHA-256" },
 53→    false,
 54→    ["sign"]
 55→  );
 56→
 57→  const signed = await crypto.subtle.sign(
 58→    "HMAC",
 59→    key,
 60→    new TextEncoder().encode(sigBasestring)
 61→  );
 62→
 63→  const computed = "v0=" + Array.from(new Uint8Array(signed))
 64→    .map((b) => b.toString(16).padStart(2, "0"))
 65→    .join("");
 66→
 67→  return computed === signature;
 68→}
