 70→// ── Helper: call Slack API with error tracking ──────────────────────
 71→
 72→async function slackApiCall(
 73→  ctx: ActionCtx,
 74→  botToken: string,
 75→  method: string,
 76→  body: Record<string, unknown>,
 77→  userId: string
 78→): Promise<{ ok: boolean; data: any; error?: string }> {
 79→  const resp = await fetch(`${SLACK_API}/${method}`, {
 80→    method: "POST",
 81→    headers: {
 82→      Authorization: `Bearer ${botToken}`,
 83→      "Content-Type": "application/json",
 84→    },
 85→    body: JSON.stringify(body),
 86→  });
 87→
 88→  const data = await resp.json();
 89→
 90→  if (data.ok) {
 91→    // Reset error tracking on success
 92→    await ctx.runMutation(internal.slack.trackSlackSuccess, { userId });
 93→    return { ok: true, data };
 94→  }
 95→
 96→  // Track the error
 97→  await ctx.runMutation(internal.slack.trackSlackError, {
 98→    userId,
 99→    error: data.error || `HTTP ${resp.status}`,
100→  });
101→
102→  // Token revoked by user in Slack settings
103→  if (data.error === "token_revoked" || data.error === "invalid_auth") {
104→    await ctx.runMutation(internal.slack.revokeSlackConnection, {
105→      userId,
106→    });
107→  }
108→
109→  return { ok: false, data, error: data.error };
110→}
