112→// ── Helper: get bot token for a user ────────────────────────────────
113→
114→async function getBotToken(
115→  ctx: ActionCtx,
116→  userId: string
117→): Promise<{ token: string; conn: any } | null> {
118→  const conn = await ctx.runQuery(internal.slack.getSlackConnection, {
119→    userId,
120→  });
121→  if (!conn || conn.status !== "active") return null;
122→
123→  try {
124→    const token = await decryptToken(conn.encryptedBotToken, conn.botTokenIv);
125→    return { token, conn };
126→  } catch (e: unknown) {
127→    const message = e instanceof Error ? e.message : String(e);
128→    console.error("Failed to decrypt Slack bot token:", message);
129→    return null;
130→  }
131→}
