135→export const notifyDraft = internalAction({
136→  args: { draftId: v.id("replyDrafts") },
137→  handler: async (ctx, args) => {
138→    const draft = await ctx.runQuery(internal.slack.getDraft, {
139→      draftId: args.draftId,
140→    });
141→    if (!draft || draft.status !== "pending_review") return;
142→
143→    const auth = await getBotToken(ctx, draft.userId);
144→    if (!auth) return;
145→
146→    const classificationLabel: Record<string, string> = {
147→      interested: "INTERESTED",
148→      replied: "REPLY",
149→      referral: "REFERRAL",
150→      out_of_office: "OOO",
151→    };
152→
153→    const label =
154→      classificationLabel[draft.classification] ||
155→      draft.classification.toUpperCase();
156→    const wordCount = (draft.draftBody || "").split(/\s+/).length;
157→
158→    const blocks = [
159→      {
160→        type: "header",
161→        text: {
162→          type: "plain_text",
163→          text: `Reply from ${draft.contactName || draft.contactEmail}`,
164→        },
165→      },
166→      {
167→        type: "section",
168→        text: {
169→          type: "mrkdwn",
170→          text: `*${label}*  |  ${draft.originalSubject}\n\n> ${draft.originalSnippet}`,
171→        },
172→      },
173→      { type: "divider" },
174→      {
175→        type: "section",
176→        text: {
177→          type: "mrkdwn",
178→          text: `*Draft reply* (${wordCount} words, confidence: ${draft.confidence || "medium"}):\n\n${draft.draftBody}`,
179→        },
180→      },
181→      {
182→        type: "actions",
183→        block_id: `reply_actions_${String(draft._id)}`,
184→        elements: [
185→          {
186→            type: "button",
187→            text: { type: "plain_text", text: "Send" },
188→            style: "primary",
189→            action_id: "approve_reply",
190→            value: String(draft._id),
191→          },
192→          {
193→            type: "button",
194→            text: { type: "plain_text", text: "Edit" },
195→            action_id: "edit_reply",
196→            value: String(draft._id),
197→          },
198→          {
199→            type: "button",
200→            text: { type: "plain_text", text: "Skip" },
201→            action_id: "skip_reply",
202→            value: String(draft._id),
203→          },
204→        ],
205→      },
206→    ];
207→
208→    const result = await slackApiCall(
209→      ctx,
210→      auth.token,
211→      "chat.postMessage",
212→      {
213→        channel: auth.conn.channelId,
214→        blocks,
215→        text: `Reply from ${draft.contactEmail}: ${draft.originalSnippet}`,
216→      },
217→      draft.userId
218→    );
219→
220→    if (result.ok && result.data.ts) {
221→      await ctx.runMutation(internal.slack.markNotified, {
222→        draftId: args.draftId,
223→        slackMessageTs: result.data.ts,
224→      });
225→    } else {
226→      console.error("Slack postMessage failed:", result.error);
227→    }
228→  },
229→});
