251→// ── Slack interactive callback handler ──────────────────────────────
252→
253→export const slackCallback = httpAction(async (ctx, request) => {
254→  // Read raw body for signature verification (must be done before parsing)
255→  const rawBody = await request.text();
256→
257→  // Verify Slack signature
258→  const isValid = await verifySlackSignature(request, rawBody);
259→  if (!isValid) {
260→    console.error("Slack signature verification failed");
261→    return new Response("Invalid signature", { status: 401 });
262→  }
263→
264→  // Parse the form data from raw body
265→  const params = new URLSearchParams(rawBody);
266→  const payloadStr = params.get("payload");
267→  if (!payloadStr) {
268→    return new Response("Missing payload", { status: 400 });
269→  }
270→
271→  const payload = JSON.parse(payloadStr);
272→
273→  // Handle view submissions (edit modal)
274→  if (payload.type === "view_submission") {
275→    const callbackId = payload.view?.callback_id || "";
276→    const draftIdStr = callbackId.replace("edit_reply_", "");
277→    const editedBody =
278→      payload.view?.state?.values?.reply_body?.body?.value || "";
279→
280→    if (editedBody && draftIdStr) {
281→      const draftId = draftIdStr as Id<"replyDrafts">;
282→      const sendData = await ctx.runMutation(
283→        internal.replyDrafts.approveDraft,
284→        { draftId, editedBody }
285→      );
286→
287→      if (sendData) {
288→        await sendApprovedReply(ctx, draftId, sendData);
289→      }
290→    }
291→
292→    return new Response("", { status: 200 });
293→  }
294→
295→  // Handle button actions
296→  const action = payload.actions?.[0];
297→  if (!action) {
298→    return new Response("No action", { status: 400 });
299→  }
300→
301→  const draftId = action.value as Id<"replyDrafts">;
302→
303→  // Get draft for context (needed for message update)
304→  const draft = await ctx.runQuery(internal.slack.getDraft, { draftId });
305→
306→  if (action.action_id === "approve_reply") {
307→    const sendData = await ctx.runMutation(
308→      internal.replyDrafts.approveDraft,
309→      { draftId }
310→    );
311→
312→    if (sendData) {
313→      const sent = await sendApprovedReply(ctx, draftId, sendData);
314→
315→      // Update the Slack message to show result
316→      if (draft?.slackMessageTs) {
317→        const slackConn = await ctx.runQuery(
318→          internal.slack.getSlackConnection,
319→          { userId: draft.userId }
320→        );
321→        if (slackConn) {
322→          const statusText = sent
323→            ? `Reply sent to ${sendData.contactEmail}.`
324→            : `Failed to send reply to ${sendData.contactEmail}. Check email connection.`;
325→          await updateSlackMessage(
326→            ctx,
327→            draft.userId,
328→            slackConn.channelId,
329→            draft.slackMessageTs,
330→            statusText
331→          );
332→        }
333→      }
334→    }
335→
336→    return new Response(
337→      JSON.stringify({
338→        replace_original: true,
339→        text: `Reply sent to ${sendData?.contactEmail || "contact"}.`,
340→      }),
341→      { status: 200, headers: { "Content-Type": "application/json" } }
342→    );
343→  }
344→
345→  if (action.action_id === "skip_reply") {
346→    await ctx.runMutation(internal.replyDrafts.rejectDraft, { draftId });
347→
348→    // Update Slack message
349→    if (draft?.slackMessageTs) {
350→      const slackConn = await ctx.runQuery(
351→        internal.slack.getSlackConnection,
352→        { userId: draft.userId }
353→      );
354→      if (slackConn) {
355→        await updateSlackMessage(
356→          ctx,
357→          draft.userId,
358→          slackConn.channelId,
359→          draft.slackMessageTs,
360→          `Reply to ${draft.contactEmail} skipped.`
361→        );
362→      }
363→    }
364→
365→    return new Response(
366→      JSON.stringify({
367→        replace_original: true,
368→        text: "Reply skipped.",
369→      }),
370→      { status: 200, headers: { "Content-Type": "application/json" } }
371→    );
372→  }
373→
374→  if (action.action_id === "edit_reply") {
375→    if (!draft) {
376→      return new Response("Draft not found", { status: 404 });
377→    }
378→
379→    // Open modal via Slack views.open API
380→    const auth = await getBotToken(ctx, draft.userId);
381→    if (auth) {
382→      await slackApiCall(ctx, auth.token, "views.open", {
383→        trigger_id: payload.trigger_id,
384→        view: {
385→          type: "modal",
386→          callback_id: `edit_reply_${String(draftId)}`,
387→          title: { type: "plain_text", text: "Edit Reply" },
388→          submit: { type: "plain_text", text: "Send" },
389→          blocks: [
390→            {
391→              type: "input",
392→              block_id: "reply_body",
393→              element: {
394→                type: "plain_text_input",
395→                action_id: "body",
396→                multiline: true,
397→                initial_value: draft.draftBody || "",
398→              },
399→              label: { type: "plain_text", text: "Reply" },
400→            },
401→          ],
402→        },
403→      }, draft.userId);
404→    }
405→
406→    return new Response("", { status: 200 });
407→  }
408→
409→  return new Response("OK", { status: 200 });
410→});
