 13→var enrichLimiter = &rateLimiter{
 14→	interval: 200 * time.Millisecond, // max 5 req/sec for enrichment
 15→}
 16→
 17→type rateLimiter struct {
 18→	mu       sync.Mutex
 19→	lastCall time.Time
 20→	interval time.Duration
 21→}
 22→
 23→func (rl *rateLimiter) wait() {
 24→	rl.mu.Lock()
 25→	defer rl.mu.Unlock()
 26→	now := time.Now()
 27→	if elapsed := now.Sub(rl.lastCall); elapsed < rl.interval {
 28→		time.Sleep(rl.interval - elapsed)
 29→	}
 30→	rl.lastCall = time.Now()
 31→}
