 44→// CheckHealth verifies consistency between a connector's config state
 45→// (connected or not) and its on-disk auth files (token.json / credentials.json).
 46→// When convexBacked is true, missing local auth files are expected (auth is server-managed).
 47→func CheckHealth(connectorID, connectorDir string, configConnected bool, convexBacked bool) HealthResult {
 48→	tokenPath := filepath.Join(connectorDir, "token.json")
 49→	credsPath := filepath.Join(connectorDir, "credentials.json")
 50→
 51→	hasToken := fileExists(tokenPath)
 52→	hasCreds := fileExists(credsPath)
 53→	hasAnyAuth := hasToken || hasCreds
 54→
 55→	if configConnected {
 56→		if convexBacked {
 57→			// Convex-backed connectors don't need local auth files.
 58→			// Validate any files that do exist, but absence is normal.
 59→			if hasToken {
 60→				if err := validateJSON(tokenPath); err != nil {
 61→					return HealthResult{ConnectorID: connectorID, Status: HealthTokenCorrupt, Message: fmt.Sprintf("token.json is corrupt: %v", err)}
 62→				}
 63→			}
 64→			return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy (server-managed)"}
 65→		}
 66→		if !hasAnyAuth {
 67→			return HealthResult{
 68→				ConnectorID: connectorID,
 69→				Status:      HealthTokenMissing,
 70→				Message:     fmt.Sprintf("config says connected but no token/credentials found in %s", connectorDir),
 71→			}
 72→		}
 73→		if hasToken {
 74→			if err := validateJSON(tokenPath); err != nil {
 75→				return HealthResult{
 76→					ConnectorID: connectorID,
 77→					Status:      HealthTokenCorrupt,
 78→					Message:     fmt.Sprintf("token.json is corrupt: %v", err),
 79→				}
 80→			}
 81→		}
 82→		if hasCreds && !hasToken {
 83→			if err := validateCredentialsFile(credsPath); err != nil {
 84→				return HealthResult{
 85→					ConnectorID: connectorID,
 86→					Status:      HealthTokenCorrupt,
 87→					Message:     fmt.Sprintf("credentials.json is corrupt: %v", err),
 88→				}
 89→			}
 90→		}
 91→		return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy"}
 92→	}
 93→
 94→	// Not connected according to config.
 95→	if hasAnyAuth {
 96→		return HealthResult{
 97→			ConnectorID: connectorID,
 98→			Status:      HealthOrphanedToken,
 99→			Message:     fmt.Sprintf("config says disconnected but auth files exist in %s", connectorDir),
100→		}
101→	}
102→	return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "clean"}
103→}
104→
105→// SaveGrantedScopes writes the granted OAuth scopes to scopes.json in the connector directory.
106→func SaveGrantedScopes(connectorDir string, scopes []string) error {
107→	data, err := json.Marshal(scopes)
108→	if err != nil {
109→		return err
110→	}
111→	return os.WriteFile(filepath.Join(connectorDir, "scopes.json"), data, 0600)
112→}
113→
114→// LoadGrantedScopes reads the granted OAuth scopes from scopes.json.
115→// Returns nil, nil if the file does not exist (graceful for old tokens).
116→func LoadGrantedScopes(connectorDir string) ([]string, error) {
117→	data, err := os.ReadFile(filepath.Join(connectorDir, "scopes.json"))
118→	if err != nil {
119→		if os.IsNotExist(err) {
120→			return nil, nil
121→		}
122→		return nil, err
123→	}
124→	var scopes []string
125→	return scopes, json.Unmarshal(data, &scopes)
126→}
127→
128→// CheckScopesSufficient returns true if all required scopes are present in granted.
129→func CheckScopesSufficient(granted, required []string) bool {
130→	set := make(map[string]bool, len(granted))
131→	for _, s := range granted {
132→		set[s] = true
133→	}
134→	for _, s := range required {
135→		if !set[s] {
136→			return false
137→		}
138→	}
139→	return true
140→}
141→
142→func fileExists(path string) bool {
143→	_, err := os.Stat(path)
144→	return err == nil
145→}
146→
147→func validateJSON(path string) error {
148→	data, err := securefile.Read(path)
149→	if err != nil {
150→		return err
151→	}
152→	var v interface{}
153→	return json.Unmarshal(data, &v)
154→}
155→
156→// validateCredentialsFile validates a credentials file that may be encrypted.
157→// Tries decryption first (new format), then falls back to plain JSON (old format).
158→func validateCredentialsFile(path string) error {
159→	data, err := readEncryptedCredentials(path)
160→	if err != nil {
161→		return err
162→	}
163→	var v interface{}
164→	return json.Unmarshal(data, &v)
165→}
