package email

import (
	"encoding/base64"
	"fmt"
	"strings"

	gm "google.golang.org/api/gmail/v1"
)

const maxRawMessageSize = 20 * 1024 * 1024 // 20MB

// SendOptions holds the fields for composing an email.
type SendOptions struct {
	To       string // recipient email
	Cc       string // optional CC
	Subject  string
	Body     string // plain text body
	ThreadID string
}

type SentMessage struct {
	MessageID string
	ThreadID  string
}

// Send sends an email via the Gmail API.
func Send(srv *gm.Service, from string, opts SendOptions) (*SentMessage, error) {
	if opts.To == "" {
		return nil, fmt.Errorf("recipient (--to) is required")
	}
	if !isValidEmail(opts.To) {
		return nil, fmt.Errorf("invalid recipient email: %s", opts.To)
	}
	if opts.Cc != "" && !isValidEmail(opts.Cc) {
		return nil, fmt.Errorf("invalid CC email: %s", opts.Cc)
	}
	if opts.Subject == "" {
		return nil, fmt.Errorf("subject (--subject) is required")
	}
	if opts.Body == "" {
		return nil, fmt.Errorf("body (--body) is required")
	}

	raw := buildRawMessage(from, opts)
	if len(raw) > maxRawMessageSize {
		return nil, fmt.Errorf("message too large (%d bytes, max %d)", len(raw), maxRawMessageSize)
	}
	msg := &gm.Message{
		Raw: base64.URLEncoding.EncodeToString([]byte(raw)),
	}
	if opts.ThreadID != "" {
		msg.ThreadId = opts.ThreadID
	}

	ctx, cancel := apiCtx()
	defer cancel()
	sent, err := srv.Users.Messages.Send("me", msg).Context(ctx).Do()
	if err != nil {
		return nil, fmt.Errorf("sending email: %w", err)
	}

	return &SentMessage{
		MessageID: sent.Id,
		ThreadID:  sent.ThreadId,
	}, nil
}

func sanitizeHeader(s string) string {
	r := strings.NewReplacer("\r", " ", "\n", " ")
	return r.Replace(s)
}

func buildRawMessage(from string, opts SendOptions) string {
	var b strings.Builder
	b.WriteString("From: " + from + "\r\n")
	b.WriteString("To: " + sanitizeHeader(opts.To) + "\r\n")
	if opts.Cc != "" {
		b.WriteString("Cc: " + sanitizeHeader(opts.Cc) + "\r\n")
	}
	b.WriteString("Subject: " + sanitizeHeader(opts.Subject) + "\r\n")
	b.WriteString("MIME-Version: 1.0\r\n")
	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
	b.WriteString("\r\n")
	b.WriteString(opts.Body)
	return b.String()
}

package email

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
	gm "google.golang.org/api/gmail/v1"
	"google.golang.org/api/option"

	"github.com/usenurge/nurgesh/internal/connector"
	"github.com/usenurge/nurgesh/internal/securefile"
)

func apiCtx() (context.Context, context.CancelFunc) {
	return context.WithTimeout(context.Background(), 30*time.Second)
}

const defaultTokenPath = ".nurge/connectors/gmail/token.json"

// NewClient creates an authenticated Gmail service from a saved token.
func NewClient(tokenPath string) (*gm.Service, error) {
	if tokenPath == "" {
		tokenPath = defaultTokenPath
	}

	tokenData, err := securefile.Read(tokenPath)
	if err != nil {
		return nil, fmt.Errorf("reading token: %w", err)
	}

	var token oauth2.Token
	if err := json.Unmarshal(tokenData, &token); err != nil {
		return nil, fmt.Errorf("parsing token: %w", err)
	}
	if token.AccessToken == "" && token.RefreshToken == "" {
		return nil, fmt.Errorf("token file contains no access or refresh token")
	}
	if !token.Expiry.IsZero() && token.Expiry.Before(time.Now()) && token.RefreshToken == "" {
		return nil, fmt.Errorf("token expired and no refresh token available")
	}

	credsData, err := connector.LoadCredentials("gmail")
	if err != nil {
		return nil, err
	}

	oauthCfg, err := google.ConfigFromJSON(credsData,
		gm.GmailReadonlyScope,
		gm.GmailSendScope,
	)
	if err != nil {
		return nil, fmt.Errorf("parsing credentials: %w", err)
	}

	ctx, cancel := apiCtx()
	defer cancel()
	client := oauthCfg.Client(ctx, &token)
	srv, err := gm.NewService(ctx, option.WithHTTPClient(client))
	if err != nil {
		return nil, fmt.Errorf("creating Gmail service: %w", err)
	}

	return srv, nil
}

